module shift_register_8(
   input                clk,
   input                rst_n,
   input                load,
   input  [7:0]         data_in,

   output reg [7:0]     obf_Q
);
    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) obf_Q <= 8'b00000000;
        else if(load) obf_Q <= data_in;
        else obf_Q <= {1'b0, obf_Q[7:1]};
    end
endmodule
